const EGTW_ITEMS: ItemTemplate[] = [
  { name: 'Acheron Blade', category: 'magic', weight: 3, description: 'Weapon (any sword), rare (requires attunement). +1 attack/damage. While on your person, you are immune to effects that turn undead. Dark Blessing (action, 1/dusk): gain 1d4+4 temporary hit points. Disheartening Strike (1/dusk): when you hit a creature, it has disadvantage on the next saving throw it makes before the end of your next turn (ignores if immune to the frightened condition).' },
  { name: 'Amulet of the Drunkard', category: 'magic', weight: 0, description: 'When you drink a pint of alcohol, regain 4d4+4 hit points. Once used, this property can\'t be used again until you finish a long rest. Uncommon.' },
  { name: 'Bloodaxe', category: 'magic', weight: 7, description: 'Weapon (greataxe), very rare (requires attunement). +2 attack/damage. On a hit against a creature that is not a Construct or Undead, deals an extra 1d6 necrotic damage. When you reduce such a creature to 0 hit points, you gain 10 temporary hit points.' },
  { name: 'Breathing Bubble', category: 'magic', weight: 0, description: 'Wondrous item, common. This small, jellyfish-like object is worn over the head like a helmet. While worn, it provides 1 hour of breathable air. It regains all expended air at dawn.' },
  { name: 'Brooch of Living Essence', category: 'magic', weight: 0, description: 'Wondrous item, uncommon (requires attunement). While wearing this brooch, spells and other effects that detect creature types treat your creature type as humanoid. Effects that detect alignment treat your alignment as neutral.' },
  { name: "Cabal's Ruin", category: 'magic', weight: 1, description: 'Cloak. +1 to saves. Absorb spell levels from spells targeting you; expend charges for +1d6/charge lightning damage. Very rare. Requires attunement.' },
  { name: 'Coin of Delving', category: 'magic', weight: 0, description: 'Wondrous item, common. This coin sheds dim light in a 5-foot radius. When dropped more than 5 feet, it produces a melodious ring upon impact. A creature holding this coin can tell how far it was dropped based on the tone of the ring.' },
  { name: 'Corpse Slayer', category: 'magic', weight: 0, description: 'Weapon (any), rare (requires attunement). +1 attack/damage. On a hit against an undead creature: deal an extra 1d8 damage of the weapon\'s type. The undead creature also has disadvantage on saving throws against being turned until the start of your next turn.' },
  { name: 'Dagger of Denial', category: 'magic', weight: 1, description: '+2 dagger. Reaction: impose disadvantage on an attack roll made against you. Rare. Requires attunement.' },
  { name: "Hunter's Coat", category: 'magic', weight: 10, description: 'Armor (leather), very rare (requires attunement). +1 AC. This armor has 3 charges and regains 1d3 expended charges daily at dawn. When you hit a creature with a weapon attack and that creature does not have all its hit points, you can expend 1 charge to deal an extra 1d10 necrotic damage to it.' },
  { name: 'Kiss of the Changebringer', category: 'magic', weight: 0, description: '3 charges. When you roll for initiative or make a Dexterity check or saving throw, use a reaction to expend 1 charge and add 1d6 to the roll. Rare. Requires attunement (rogue).' },
  { name: 'Night Caller', category: 'magic', weight: 0, description: 'Whistle carved from undead bone. As an action during darkness, blow it to target a corpse or pile of bones within 300 ft. — it animates as a skeleton or zombie (your choice) under your control for 24 hours. Single use per blowing; the creature isn\'t created by the animate dead spell. Uncommon.' },
  { name: 'Potion of Possibility', category: 'magic', weight: 0.5, description: 'Potion, very rare. When you drink this potion, you gain 2 Fragments of Possibility, each lasting for 8 hours. When you make an attack roll, ability check, or saving throw while you have a Fragment, you can expend the Fragment to roll an extra d20 and choose which result to use. You can also use a Fragment when a creature makes an attack roll against you to roll a d20 and choose which roll the attacker uses. You can\'t gain more Fragments while you have any remaining. Unused Fragments vanish when the duration ends.' },
  { name: 'Ring of Obscuring', category: 'magic', weight: 0, description: 'Ring, uncommon (requires attunement). This ring has 3 charges and regains 1d3 expended charges daily at dawn. While wearing it, you can use an action and expend 1 charge to cast the fog cloud spell from the ring, centered on you. The spell lasts for 1 minute (no concentration required).' },
  { name: 'Ring of Temporal Salvation', category: 'magic', weight: 0, description: 'Ring, rare (requires attunement). If you die while wearing this ring, you vanish and reappear at the start of your next turn in an unoccupied space within 5 feet of where you fell. You have a number of hit points equal to 3d6 + your Constitution modifier. If your hit point maximum is lower than that number, it rises to that number. Your exhaustion level is reduced by 1. The ring then turns to dust.' },
  { name: 'Silencer', category: 'magic', weight: 2, description: 'Shortsword. Attacks made with it produce no sound. Uncommon.' },
  { name: 'Speaking Stone', category: 'magic', weight: 0.5, description: 'Linked to one other stone; cast sending between them at will. Very rare.' },
  { name: 'Sword of Fathoms', category: 'magic', weight: 2, description: 'Longsword. On a natural 20: +2d6 necrotic damage, and the target must succeed on a DC 14 Con save or gain 1 level of exhaustion (removed by a short or long rest). Uncommon. Requires attunement.' },
  { name: 'Verminshroud', category: 'magic', weight: 1, description: 'Cloak made from giant rat skin. Advantage on Stealth checks; you can speak with Small or smaller beasts; advantage on Perception checks relying on smell; darkvision 60 ft. Charges (spells): spider climb (2, no concentration), web (2), giant insect (3), insect plague (5). Legendary. Requires attunement.' },
  { name: 'Wavethreader', category: 'magic', weight: 1, description: 'Cloak woven from strands of solid water. You can move through liquids as if they were difficult terrain instead of being impeded. Cast freedom of movement on yourself using the cloak as a focus. Rare. Requires attunement.' },
];

