const tag = <B extends BookId>(arr: ItemTemplate[], book: B): ItemTemplate[] =>
  arr.map(i => ({ ...i, sourceBook: book }));

export const ALL_ITEMS: ItemTemplate[] = [
  ...tag(WEAPONS,     'PHB'),
  ...tag(ARMOR,       'PHB'),
  ...tag(PACKS,       'PHB'),
  ...tag(GEAR,        'PHB'),
  ...tag(TOOLS,       'PHB'),
  ...tag(CONSUMABLES, 'PHB'),
  ...tag(MAGIC_ITEMS, 'DMG'),
  ...tag(DMG_EXTRA,   'DMG'),
  ...tag(XGTE_ITEMS,  'XGtE'),
  ...tag(TCE_ITEMS,   'TCE'),
  ...tag(EGTW_ITEMS,  'EGtW'),
  ...tag(FTOD_ITEMS,  'FToD'),
  ...tag(GGR_ITEMS,   'GGR'),
  ...tag(SJA_ITEMS,   'SJA'),
  ...tag(SCOC_ITEMS,  'SCoC'),
  ...tag(ERLW_ITEMS,  'ERLW'),
  ...tag(TREASURE,    'PHB'),
];

export function searchItems(query: string, enabledBooks: BookId[], limit = 8): ItemTemplate[] {
  if (!query.trim()) return [];
  const q = query.toLowerCase();
  const bookSet = new Set<BookId>(enabledBooks);
  const results: Array<{ item: ItemTemplate; score: number }> = [];

  for (const item of ALL_ITEMS) {
    if (item.sourceBook && !bookSet.has(item.sourceBook)) continue;
    const name = item.name.toLowerCase();
    if (name.startsWith(q)) {
      results.push({ item, score: 2 });
    } else if (name.includes(q)) {
      results.push({ item, score: 1 });
    }
  }

  results.sort((a, b) => b.score - a.score || a.item.name.localeCompare(b.item.name));
  return results.slice(0, limit).map(r => r.item);
}

export function getItemByName(name: string): ItemTemplate | undefined {
  const lower = name.toLowerCase();
  return ALL_ITEMS.find(i => i.name.toLowerCase() === lower);
}
